/**
 * Analytics Validation Schema Tests
 * Tests the analytics tracking and metrics validation
 */

import { 
  PageViewEventSchema,
  NewsletterEngagementEventSchema,
  UserPreferenceEventSchema,
  PerformanceMetricSchema,
  AnalyticsSessionSchema,
  AnalyticsEventSchema,
  NewsletterMetricsSchema,
  AudienceSegmentSchema,
  ContentPerformanceSchema,
  SystemMetricsSchema,
  AnalyticsDashboardSchema,
  isValidEventType,
  calculateEngagementRate,
  segmentAudience,
  getTopPerformingContent
} from '../analytics';

describe('Analytics Validation Schemas', () => {
  describe('PageViewEventSchema', () => {
    it('should validate complete page view event', () => {
      const event = {
        page: '/morning',
        referrer: 'https://google.com',
        userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        sessionDuration: 120000,
        scrollDepth: 85,
        timeOnPage: 45000,
        exitPage: false,
      };

      expect(event).toBeValidZodSchema(PageViewEventSchema);
    });

    it('should validate minimal page view event', () => {
      const event = {
        page: '/afternoon',
        userAgent: 'Mozilla/5.0',
        sessionDuration: 30000,
        scrollDepth: 50,
        timeOnPage: 15000,
        exitPage: true,
      };

      expect(event).toBeValidZodSchema(PageViewEventSchema);
    });

    it('should reject invalid scroll depth', () => {
      const event = {
        page: '/morning',
        userAgent: 'Mozilla/5.0',
        sessionDuration: 120000,
        scrollDepth: 150, // Invalid: over 100
        timeOnPage: 45000,
        exitPage: false,
      };

      expect(event).toHaveZodError(PageViewEventSchema, 'Number must be less than or equal to 100');
    });

    it('should reject negative time values', () => {
      const event = {
        page: '/morning',
        userAgent: 'Mozilla/5.0',
        sessionDuration: -1000, // Invalid: negative
        scrollDepth: 85,
        timeOnPage: 45000,
        exitPage: false,
      };

      expect(event).toHaveZodError(PageViewEventSchema, 'Number must be greater than or equal to 0');
    });
  });

  describe('NewsletterEngagementEventSchema', () => {
    it('should validate newsletter engagement event', () => {
      const event = {
        action: 'open',
        newsletterId: 'newsletter_123',
        articleId: 'article_456',
        linkUrl: 'https://transferjuice.com/morning',
        position: 2,
        deviceType: 'mobile',
        timeToAction: 30000,
      };

      expect(event).toBeValidZodSchema(NewsletterEngagementEventSchema);
    });

    it('should validate minimal engagement event', () => {
      const event = {
        action: 'click',
        newsletterId: 'newsletter_789',
        deviceType: 'desktop',
        timeToAction: 15000,
      };

      expect(event).toBeValidZodSchema(NewsletterEngagementEventSchema);
    });

    it('should reject invalid action type', () => {
      const event = {
        action: 'invalid_action',
        newsletterId: 'newsletter_123',
        deviceType: 'desktop',
        timeToAction: 15000,
      };

      expect(event).toHaveZodError(NewsletterEngagementEventSchema, 'Invalid enum value');
    });

    it('should reject invalid device type', () => {
      const event = {
        action: 'open',
        newsletterId: 'newsletter_123',
        deviceType: 'smartwatch', // Invalid
        timeToAction: 15000,
      };

      expect(event).toHaveZodError(NewsletterEngagementEventSchema, 'Invalid enum value');
    });
  });

  describe('UserPreferenceEventSchema', () => {
    it('should validate user preference change', () => {
      const event = {
        preferenceType: 'team_selection',
        oldValue: ['arsenal'],
        newValue: ['arsenal', 'chelsea'],
        changeReason: 'user_action',
      };

      expect(event).toBeValidZodSchema(UserPreferenceEventSchema);
    });

    it('should validate subscription status change', () => {
      const event = {
        preferenceType: 'subscription_status',
        oldValue: 'active',
        newValue: 'paused',
        changeReason: 'user_action',
      };

      expect(event).toBeValidZodSchema(UserPreferenceEventSchema);
    });

    it('should reject invalid preference type', () => {
      const event = {
        preferenceType: 'invalid_type',
        oldValue: 'old',
        newValue: 'new',
        changeReason: 'user_action',
      };

      expect(event).toHaveZodError(UserPreferenceEventSchema, 'Invalid enum value');
    });
  });

  describe('AnalyticsSessionSchema', () => {
    it('should validate complete analytics session', () => {
      const session = {
        id: 'session_123',
        userId: 'user_456',
        startTime: new Date('2024-01-15T10:00:00Z'),
        endTime: new Date('2024-01-15T10:30:00Z'),
        duration: 1800000,
        pageViews: 5,
        bounceRate: 0.2,
        deviceInfo: {
          type: 'desktop',
          browser: 'Chrome',
          os: 'Windows',
          screenResolution: '1920x1080',
        },
        location: {
          country: 'GB',
          city: 'London',
          timezone: 'Europe/London',
        },
        referralSource: 'google',
        utm: {
          source: 'google',
          medium: 'organic',
          campaign: 'transfer_news',
        },
      };

      expect(session).toBeValidZodSchema(AnalyticsSessionSchema);
    });

    it('should reject invalid bounce rate', () => {
      const session = {
        id: 'session_123',
        startTime: new Date(),
        duration: 1800000,
        pageViews: 5,
        bounceRate: 1.5, // Invalid: over 1.0
        deviceInfo: {
          type: 'desktop',
          browser: 'Chrome',
          os: 'Windows',
        },
      };

      expect(session).toHaveZodError(AnalyticsSessionSchema, 'Number must be less than or equal to 1');
    });
  });

  describe('NewsletterMetricsSchema', () => {
    it('should validate newsletter performance metrics', () => {
      const metrics = {
        newsletterId: 'newsletter_123',
        briefingType: 'morning',
        sentAt: new Date('2024-01-15T08:00:00Z'),
        totalRecipients: 10000,
        delivered: 9850,
        opened: 3500,
        clicked: 850,
        unsubscribed: 25,
        bounced: 150,
        complained: 5,
        deliveryRate: 0.985,
        openRate: 0.355,
        clickRate: 0.243,
        clickThroughRate: 0.086,
        unsubscribeRate: 0.0025,
        bounceRate: 0.015,
        complaintRate: 0.0005,
        topLinks: [
          { url: 'https://transferjuice.com/article/123', clicks: 350 },
          { url: 'https://transferjuice.com/subscribe', clicks: 150 },
        ],
        engagementByDevice: {
          desktop: { opens: 2100, clicks: 510 },
          mobile: { opens: 1200, clicks: 280 },
          tablet: { opens: 200, clicks: 60 },
        },
        geographicPerformance: [
          { country: 'GB', opens: 1500, clicks: 400 },
          { country: 'US', opens: 1200, clicks: 300 },
        ],
      };

      expect(metrics).toBeValidZodSchema(NewsletterMetricsSchema);
    });

    it('should reject metrics with inconsistent rates', () => {
      const metrics = {
        newsletterId: 'newsletter_123',
        briefingType: 'morning',
        sentAt: new Date(),
        totalRecipients: 1000,
        delivered: 950,
        opened: 350,
        clicked: 85,
        unsubscribed: 2,
        bounced: 50,
        complained: 1,
        deliveryRate: 0.95,
        openRate: 0.50, // Inconsistent: should be 350/950 = 0.368
        clickRate: 0.24,
        clickThroughRate: 0.09,
        unsubscribeRate: 0.002,
        bounceRate: 0.05,
        complaintRate: 0.001,
        topLinks: [],
        engagementByDevice: {
          desktop: { opens: 200, clicks: 50 },
          mobile: { opens: 100, clicks: 25 },
          tablet: { opens: 50, clicks: 10 },
        },
        geographicPerformance: [],
      };

      expect(metrics).toHaveZodError(NewsletterMetricsSchema, 'Open rate calculation is inconsistent');
    });
  });

  describe('ContentPerformanceSchema', () => {
    it('should validate content performance data', () => {
      const performance = {
        contentId: 'article_123',
        contentType: 'article',
        publishedAt: new Date('2024-01-15T08:00:00Z'),
        views: 15000,
        uniqueVisitors: 12000,
        averageTimeOnPage: 120000,
        bounceRate: 0.35,
        shareCount: 250,
        commentCount: 45,
        emailClicks: 850,
        socialReferrals: 300,
        searchReferrals: 400,
        directTraffic: 500,
        conversionRate: 0.08,
        engagementScore: 85,
        topReferrers: [
          { source: 'twitter.com', visits: 200 },
          { source: 'facebook.com', visits: 100 },
        ],
        timeBasedMetrics: [
          { hour: 8, views: 2000 },
          { hour: 9, views: 3500 },
          { hour: 10, views: 2800 },
        ],
      };

      expect(performance).toBeValidZodSchema(ContentPerformanceSchema);
    });
  });

  describe('Utility Functions', () => {
    describe('isValidEventType', () => {
      it('should validate known event types', () => {
        expect(isValidEventType('page_view')).toBe(true);
        expect(isValidEventType('newsletter_engagement')).toBe(true);
        expect(isValidEventType('user_preference_change')).toBe(true);
        expect(isValidEventType('subscription_change')).toBe(true);
      });

      it('should reject unknown event types', () => {
        expect(isValidEventType('unknown_event')).toBe(false);
        expect(isValidEventType('')).toBe(false);
        expect(isValidEventType('INVALID')).toBe(false);
      });
    });

    describe('calculateEngagementRate', () => {
      it('should calculate correct engagement rate', () => {
        const rate = calculateEngagementRate(500, 2000);
        expect(rate).toBe(0.25);
      });

      it('should handle zero total views', () => {
        const rate = calculateEngagementRate(100, 0);
        expect(rate).toBe(0);
      });

      it('should handle edge cases', () => {
        expect(calculateEngagementRate(0, 1000)).toBe(0);
        expect(calculateEngagementRate(1000, 1000)).toBe(1);
      });
    });

    describe('segmentAudience', () => {
      it('should segment audience by engagement level', () => {
        const users = [
          { id: '1', engagementScore: 90 },
          { id: '2', engagementScore: 60 },
          { id: '3', engagementScore: 30 },
          { id: '4', engagementScore: 10 },
        ];

        const segments = segmentAudience(users, 'engagement');
        expect(segments.high).toHaveLength(1);
        expect(segments.medium).toHaveLength(1);
        expect(segments.low).toHaveLength(2);
      });

      it('should segment audience by activity level', () => {
        const users = [
          { id: '1', lastActiveAt: new Date('2024-01-15') },
          { id: '2', lastActiveAt: new Date('2024-01-10') },
          { id: '3', lastActiveAt: new Date('2023-12-01') },
        ];

        const segments = segmentAudience(users, 'activity');
        expect(segments.active).toBeDefined();
        expect(segments.inactive).toBeDefined();
      });
    });

    describe('getTopPerformingContent', () => {
      it('should return top performing content', () => {
        const content = [
          { id: '1', views: 1000, engagementRate: 0.8 },
          { id: '2', views: 2000, engagementRate: 0.6 },
          { id: '3', views: 500, engagementRate: 0.9 },
        ];

        const top = getTopPerformingContent(content, 2, 'views');
        expect(top).toHaveLength(2);
        expect(top[0].id).toBe('2'); // Highest views
        expect(top[1].id).toBe('1');
      });

      it('should sort by engagement rate', () => {
        const content = [
          { id: '1', views: 1000, engagementRate: 0.8 },
          { id: '2', views: 2000, engagementRate: 0.6 },
          { id: '3', views: 500, engagementRate: 0.9 },
        ];

        const top = getTopPerformingContent(content, 2, 'engagement');
        expect(top).toHaveLength(2);
        expect(top[0].id).toBe('3'); // Highest engagement
        expect(top[1].id).toBe('1');
      });
    });
  });
});